#!/usr/bin/env python3
"""Activity UI: upcoming/past split, time ranges for opens, updated client view"""
import base64, os, sys
if not os.path.exists("frontend/src/pages"):
    print("Error: Run from ~/seller-portal"); sys.exit(1)
files = {}
files["frontend/src/pages/AdminPropertyDetail.jsx"] = ""
files["frontend/src/pages/ClientDashboard.jsx"] = ""

for path, data in files.items():
    content = base64.b64decode(data)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(content)
    print(f"  Updated: {path} ({len(content):,} bytes)")
print()
print("Now run:")
print('  git add -A && git commit -m "Activity UI: upcoming/past split, time ranges for opens" && git push')
